import sysfrom PyQt6.QtWidgets import QApplicationfrom app.ui.main_window import MainWindowfrom app.ui.login_window import LoginWindowfrom app.controllers import ArchiveControllerfrom app.database import Base, engineBase.metadata.create_all(bind=engine)def main():    app = QApplication(sys.argv)    app.setStyle('Fusion')    controller = ArchiveController()    login_window = LoginWindow(controller)    main_window = None #will create after the login    def show_main_app(role):        nonlocal main_window        print(f"Logged in as: {role}")        login_window.close()        main_window = MainWindow()        #main_window.set_user_role(role)        main_window.show()    login_window.login_successful.connect(show_main_app)    login_window.show()    sys.exit(app.exec())if __name__ == "__main__":    main()